/**
 * Unit tests for safe-command-retry PermissionDenied hook
 * Tests retry logic for known-safe Bash commands after denial
 */

import { describe, test, expect, vi, beforeEach } from 'vitest';
import { safeCommandRetry } from '../../permission-denied/safe-command-retry.js';
import type { HookInput } from '../../types.js';

// Mock the common module
vi.mock('../../lib/common.js', async () => {
  const actual = await vi.importActual<typeof import('../../lib/common.js')>('../../lib/common.js');
  return {
    ...actual,
    logHook: vi.fn(),
    outputSilentSuccess: () => ({ continue: true, suppressOutput: true }),
  };
});

/**
 * Create a mock HookInput for a denied Bash command
 */
function createDeniedBashInput(command: string): HookInput {
  return {
    tool_name: 'Bash',
    session_id: 'test-session-123',
    tool_input: { command },
    project_dir: '/test/project',
    hook_event: 'PermissionDenied',
  };
}

describe('safe-command-retry', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  describe('Known-safe commands return {retry: true}', () => {
    const safeRetryCommands = [
      // Git read-only
      'git status',
      'git log --oneline -10',
      'git diff HEAD~1',
      'git branch -a',
      'git show HEAD',
      'git fetch origin',
      'git remote -v',
      'git tag --list',

      // Basic shell read-only
      'ls',
      'ls -la /some/path',
      'pwd',
      'cat file.txt',
      'head -n 10 file.txt',
      'tail -f log.txt',
      'wc -l file.txt',
      'find . -name "*.ts"',
      'which node',
      'type python',
      'env',
      'printenv',
      'printenv PATH',

      // Package manager read-only
      'npm list',
      'npm ls --depth=0',
      'npm outdated',
      'npm audit',
      'pnpm list',
      'pnpm audit',

      // Docker read-only
      'docker ps',
      'docker images',
      'docker logs container-name',
      'docker inspect my-container',

      // GitHub CLI read-only
      'gh issue list',
      'gh pr view 456',
      'gh repo view',
      'gh workflow status',

      // Test/lint commands
      'npm run test',
      'npm run lint',
      'npm run typecheck',
      'npm run format',
      'pytest',
      'pytest tests/ -v',
    ];

    test.each(safeRetryCommands)('retries: %s', (command) => {
      // Arrange
      const input = createDeniedBashInput(command);

      // Act
      const result = safeCommandRetry(input);

      // Assert
      expect(result.continue).toBe(true);
      expect(result.hookSpecificOutput?.retry).toBe(true);
      expect(result.hookSpecificOutput?.hookEventName).toBe('PermissionDenied');
      expect(result.hookSpecificOutput?.additionalContext).toContain('incorrectly denied');
    });
  });

  describe('Compound commands NOT retried', () => {
    const compoundCommands = [
      'git status && rm -rf /',
      'ls -la || echo "failed"',
      'cat file.txt | grep secret',
      'git status; rm -rf /',
      'git status\ngit diff',
    ];

    test.each(compoundCommands)('does not retry compound: %s', (command) => {
      // Arrange
      const input = createDeniedBashInput(command);

      // Act
      const result = safeCommandRetry(input);

      // Assert
      expect(result.continue).toBe(true);
      expect(result.hookSpecificOutput?.retry).toBeUndefined();
    });
  });

  describe('Reject patterns NOT retried', () => {
    const rejectCommands = [
      'git reset --hard',
      'git push --force origin main',
      'git push -f origin main',
      'git checkout -- .',
      'git checkout .',
      'git clean -fd',
      'rm -rf /tmp/data',
      'rm file.txt',
      'chmod 777 /etc/passwd',
    ];

    test.each(rejectCommands)('does not retry rejected: %s', (command) => {
      // Arrange
      const input = createDeniedBashInput(command);

      // Act
      const result = safeCommandRetry(input);

      // Assert
      expect(result.continue).toBe(true);
      expect(result.hookSpecificOutput?.retry).toBeUndefined();
    });
  });

  describe('Unknown commands NOT retried', () => {
    const unknownCommands = [
      'npm install some-package',
      'npm run build',
      'curl http://example.com',
      'wget http://example.com',
      'sudo apt install nginx',
      'pip install requests',
      'docker run alpine',
      'git checkout feature-branch',
      'git push origin main',
      'ssh user@host',
      'scp file.txt remote:/path',
    ];

    test.each(unknownCommands)('does not retry unknown: %s', (command) => {
      // Arrange
      const input = createDeniedBashInput(command);

      // Act
      const result = safeCommandRetry(input);

      // Assert
      expect(result.continue).toBe(true);
      expect(result.hookSpecificOutput?.retry).toBeUndefined();
    });
  });

  describe('Edge cases', () => {
    test('empty command returns silent success', () => {
      // Arrange
      const input = createDeniedBashInput('');

      // Act
      const result = safeCommandRetry(input);

      // Assert
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      expect(result.hookSpecificOutput?.retry).toBeUndefined();
    });

    test('undefined command returns silent success', () => {
      // Arrange
      const input: HookInput = {
        tool_name: 'Bash',
        session_id: 'test-session-123',
        tool_input: {},
        project_dir: '/test/project',
      };

      // Act
      const result = safeCommandRetry(input);

      // Assert
      expect(result.continue).toBe(true);
      expect(result.hookSpecificOutput?.retry).toBeUndefined();
    });

    test('command with leading whitespace is normalized', () => {
      // Arrange
      const input = createDeniedBashInput('  git status');

      // Act
      const result = safeCommandRetry(input);

      // Assert — normalizeSingle trims whitespace
      expect(result.hookSpecificOutput?.retry).toBe(true);
    });

    test('reject pattern takes priority over safe pattern', () => {
      // "git push -f" matches reject, even though "git push" could theoretically match
      const input = createDeniedBashInput('git push -f origin main');
      const result = safeCommandRetry(input);

      expect(result.hookSpecificOutput?.retry).toBeUndefined();
    });

    test('result structure has correct shape for retry', () => {
      // Arrange
      const input = createDeniedBashInput('git status');

      // Act
      const result = safeCommandRetry(input);

      // Assert — verify full result shape
      expect(result).toEqual({
        continue: true,
        suppressOutput: true,
        hookSpecificOutput: {
          hookEventName: 'PermissionDenied',
          retry: true,
          additionalContext: expect.stringContaining('incorrectly denied'),
        },
      });
    });

    test('result structure has correct shape for silent success', () => {
      // Arrange
      const input = createDeniedBashInput('npm install something');

      // Act
      const result = safeCommandRetry(input);

      // Assert
      expect(result).toEqual({
        continue: true,
        suppressOutput: true,
      });
    });
  });
});
